# Breadth-First Search + Sliding Window Solution
# TC: O(n), SC: O(n)
class Solution:
    def canReach(self, s: str, minJump: int, maxJump: int) -> bool:
        n = len(s)
        farthest = 0

        queue = deque([0])
        while queue:
            i = queue.popleft()
            if i == n - 1:
                return True

            start = max(i + minJump, farthest + 1)
            end = min(i + maxJump, n - 1)

            for j in range(start, end + 1):
                if s[j] == '0':
                    queue.append(j)

            farthest = end

        return False



# TLE
# s = "", minJump = 1, maxJump = 49999
# Dynamic Programming + Memoization Approach
# TC: O(n*j), SC: O(n)
class Solution:
    def canReach(self, s: str, minJump: int, maxJump: int) -> bool:
        if s[-1] != '0':
            return False

        cache = {}
        def rec(i):
            if i in cache:
                return cache[(i)]
                
            if i == len(s) - 1:
                return True

            for j in range(i + minJump, min(i + maxJump, len(s) - 1) + 1):
                if s[j] == '0' and rec(j):
                    return True

            cache[(i)] = False
            return False

        return rec(0)